sp_widget.script:
(function() {
  // Query the x_1086142_promptce_prompt table for records where display_on_portal is true
  var gr = new GlideRecord('x_1086142_promptce_prompt');
  gr.addQuery('display_on_portal', true);
  gr.query();
  data.prompts = [];
  while (gr.next()) {
    data.prompts.push({
      sys_id: gr.getValue('sys_id'),
      number: gr.getValue('number'),
      user_input: gr.getValue('user_input'),
      expanded_prompt: gr.getValue('expanded_prompt'),
      submitter: gr.getDisplayValue('submitter'),
    });
  }
})();
